#include<bits/stdc++.h>
using namespace std;
long long b[1000010],n;
struct segment_tree
{
    struct node
    {
        long long l,r,max1;
        long long lson,rson;
        long long tag,tag1;
        node():tag(0),tag1(-2e13){}
    }a[3000010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].max1=max(a[a[x].lson].max1,a[a[x].rson].max1);
    }
    void pushdown(long long x)
    {
        long long mid=(a[x].l+a[x].r)>>1;
        long long ls=a[x].lson,rs=a[x].rson;
        long long tg=a[x].tag,tg1=a[x].tag1;
        if(tg1!=(-2e13))
        {
            a[ls].tag=a[rs].tag=0;
            a[ls].max1=tg1;
            a[ls].tag1=tg1;
            a[rs].max1=tg1;
            a[rs].tag1=tg1;
        }
        a[ls].max1+=tg;
        a[ls].tag+=tg;
        a[rs].max1+=tg;
        a[rs].tag+=tg;
        a[x].tag=0;
        a[x].tag1=-2e13;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].max1=b[l];
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].max1+=z;
            a[x].tag+=z;
            return;
        }
        pushdown(x);
        add(a[x].lson,l,r,z);
        add(a[x].rson,l,r,z);
        pushup(x);
    }
    void update(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].max1=z;
            a[x].tag1=z;
            a[x].tag=0;
            return;
        }
        pushdown(x);
        update(a[x].lson,l,r,z);
        update(a[x].rson,l,r,z);
        pushup(x);
    }
    long long getmax(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return -2e13;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].max1;
        }
        pushdown(x);
        return max(getmax(a[x].lson,l,r),getmax(a[x].rson,l,r));
    }
}t;
int main()
{
    long long q;
    scanf("%lld%lld",&n,&q);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    t.init(1,n);
    while(q--)
    {
        long long op,l,r,x;
        scanf("%lld%lld%lld",&op,&l,&r);
        if(op!=3)
        {
            scanf("%lld",&x);
        }
        if(op==1)
        {
            t.update(1,l,r,x);
        }
        else if(op==2)
        {
            t.add(1,l,r,x);
        }
        else
        {
            printf("%lld\n",t.getmax(1,l,r));
        }
    }
    return 0;
}
